//-------------------------------------------------------------------------
//  f_afterEmpNo :  세무조사 id 여부 조회 - 증빙관리권한 조회후
//-------------------------------------------------------------------------
scwin.f_afterEmpNo = function () {
  console.log("=== f_afterEmpNo (증빙관리권한 조회후)");
  // debugger;
  // var valueObject = window.dialogArguments;

  scwin.valueObject = $c.data.getParameter($p);
  if (!$c.gus.cfIsNull($p, scwin.valueObject)) {
    if (scwin.valueObject["slipNo"] != "") {
      ed_slipNo.setValue(scwin.valueObject["slipNo"]);
      lc_slipKndCd.setValue(scwin.valueObject["slipKndCd"]);
    }
    if (scwin.valueObject["apprReqNo"] != "") {
      ed_apprReqNo.setValue(scwin.valueObject["apprReqNo"]);
    }
  }
  if (scwin.slipNo != "") {
    ed_slipNo.setValue(scwin.slipNo);
  }
  if (scwin.apprReqNo != "") {
    ed_apprReqNo.setValue(scwin.apprReqNo);
  }
  if (ed_slipNo.getValue() != "" || ed_apprReqNo.getValue() != "") {
    scwin.f_Retrieve();
  }

  // var g_sLoginDept = "<%=login.getAcctDeptCd()%>";
  // var vEmpNo= "<%=login.getEmpNo()%>"
  ed_deptCd.setValue(scwin.acctDeptCd);
  if (scwin.acctDeptCd != '00009') {
    if (scwin.userEmpNo == "198015" || scwin.userEmpNo == "198078" || scwin.userEmpNo == "171577") {//BIDC 이재설 과장, 최현주 대리 추가 (박경진대리 퇴사로 최현주 대리 변경)
    } else {
      scwin.f_changeCheck(); // 작성부서 변경권한 체크 (FI627 : 자회사 증빙관리 부서변경 조회 권한)
    }
  } else {}

  // 포르테에서 호출할시 제어
  if (scwin.fromClsCd == "PORTE") {
    console.log("  ==--== 비활성 : 전표번호 (포르테에서 호출)");
    $c.gus.cfDisableObjects($p, [ed_slipNo]);
  } else {
    $c.gus.cfEnableObjects($p, [ed_slipNo]);
    console.log("  ==--== 활성 : 전표번호 (포르테에서 미호출)");
  }
};

