//-------------------------------------------------------------------------
// 팝업체크
// 파라미터
//          gubun      : 4
//          inObj      : this (?)
//          pairObj    : ed_deptCd / ed_deptNm
//          isCode     : 코드   - 기존 null --> false (파라미터 갯수 맞춤)
//                       코드명 - true
//-------------------------------------------------------------------------
scwin.f_ChkOpenCommonPopUp = function (gubun, inObj, pairObj, isCode) {
  console.log("=== f_ChkOpenCommonPopUp ( gubun[ " + gubun + " ]  inObj[ " + inObj + " ]  pairObj[ " + pairObj + " ]  isCode[ " + isCode + " ] 4:작성부서)");

  //값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) return;

  // // inObj가 코드 필드일 경우 팝업
  // if (isCode == null || isCode == true){
  //     if(!$c.gus.cfCanOpenPopup(inObj, pairObj))	return;
  // }else{ // inObj가 코드명 필드일 경우 팝업
  //     if(!$c.gus.cfCanOpenPopup(inObj, pairObj))	return;
  // }

  //짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  //검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);

  // inObj가 코드 필드일 경우 팝업
  if (isCode == null || isCode == true) {
    scwin.f_OpenCommonPopUp(gubun, pVal, '', 'T', 'T');
  } else {
    // inObj가 코드명 필드일 경우 팝업
    scwin.f_OpenCommonPopUp(gubun, '', pVal, 'T', 'T');
  }
};

