//-------------------------------------------------------------------------
// function name : f_userToExcel1()
// function desc : 엑셀저장 - 매출/매입 거래명세서
// function Parameter : gr_groupCode : 그리드명, gridName : 엑셀저장명 (매출입 List)
//-------------------------------------------------------------------------
scwin.f_userToExcel1 = async function (temp_grid, gridName) {
  // var objGrd = eval(gr_evid1);
  // var objDs = eval(objGrd.DataID) ;
  // if (objDs.CountRow <= 0)
  // {
  //     cfAlertMsg(MSG_CM_WRN_009,Array("데이타"));  // 출력할 @이(가) 없습니다.
  // 	return false
  // }
  // cfGridToExcel(gr_evid1, gridName,"C:\\" + gridName + ".xls", 4+8+16);

  if (ds_evid1.getTotalRow() == 0) {
    await $c.gus.cfAlertMsg($p, $c.data.getMessage($p, MSG_CM_WRN_009, "데이타"));
    return false;
  }
  var sheetTitle = gridName; // 매출입 List
  let cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
  if (cfrm) {
    let options = {
      fileName: sheetTitle + ".xlsx",
      sheetName: sheetTitle
    };
    if (scwin.isCorCardAcYn == true) {
      // 법인카드 정산여부
      $c.data.downloadGridViewExcel($p, gr_evid2, options);
    } else {
      $c.data.downloadGridViewExcel($p, gr_evid1, options);
    }
  }
};

