//-------------------------------------------------------------------------
// save (파일 처리)
//-------------------------------------------------------------------------
scwin.save = async function () {
  console.log("======= save (파일 처리)   slipNo [" + scwin.slipNo + "]");

  // if ( scwin.slipNo == "" ) {
  //     await $c.win.alert("전표번호가 없으면 파일 처리가 안됩니다.");
  //     return;
  // }

  let fileList = udc_fileUpload.getData();
  let iCnt = 0;
  let dCnt = 0;
  for (let idx in fileList) {
    let rowStatus = fileList[idx].rowStatus;
    switch (rowStatus) {
      case "C":
        iCnt++;
        break;
      case "D":
        dCnt++;
        break;
      default:
        break;
    }
  }
  //등록, 삭제가 둘다 있는 경우
  if (iCnt > 0 && dCnt > 0) {
    await $c.win.alert($p, "신규등록과 삭제를 같이 할 수 없습니다.");
    return;
  } else {
    if (iCnt > 0) {
      scwin.fileSubmit();
    } else if (dCnt > 0) {
      scwin.fileDelete();
    } else {
      await $c.gus.cfAlertMsg($p, $c.data.getMessage($p, MSG_CM_ERR_049, "등록할 파일"));
      return;
    }
  }
};

